    "section": {
      "type": "main-blog-post",
      "blocks": {
        "blog-post-title": {
          "type": "text",
          "name": "Title",
          "static": true,
          "settings": {
            "text": "<h1>{{ article.title }}</h1>",
            "width": "100%",
            "max_width": "normal",
            "alignment": "center",
            "type_preset": "h2",
            "font": "var(--font-primary--family)",
            "font_size": "",
            "line_height": "normal",
            "letter_spacing": "normal",
            "case": "none",
            "wrap": "pretty",
            "color": "",
            "background": false,
            "background_color": "#00000026",
            "corner_radius": 0,
            "padding-block-start": 0,
            "padding-block-end": 0,
            "padding-inline-start": 0,
            "padding-inline-end": 0
          },
          "blocks": {}
        },
        "blog-post-details": {
          "type": "_blog-post-info-text",
          "name": "Details",
          "static": true,
          "settings": {
            "show_date": true,
            "show_author": false,
            "type_preset": "",
            "alignment": "center",
            "show_alignment": true,
            "padding-block-start": 24,
            "padding-block-end": 0
          },
          "blocks": {}
        },
        "blog-post-image": {
          "type": "_blog-post-featured-image",
          "name": "Featured image",
          "static": true,
          "settings": {
            "image_ratio": "landscape",
            "width": "fill",
            "custom_width": 100,
            "width_mobile": "fill",
            "custom_width_mobile": 100,
            "height": "fit",
            "border": "none",
            "border_width": 1,
            "border_opacity": 100,
            "border_radius": 0,
            "padding-block-start": 0,
            "padding-block-end": 0,
            "padding-inline-start": 0,
            "padding-inline-end": 0
          },
          "blocks": {}
        },
        "blog-post-content": {
          "type": "_blog-post-content",
          "static": true,
          "settings": {},
          "blocks": {}
        }
      },
      "settings": {
        "content_direction": "column",
        "gap": 32,
        "color_scheme": "",
        "padding-block-start": 40,
        "padding-block-end": 80
      }
    }
  },
  "order": [
    "section"
  ]
}

